package com.s4.belsson.data.api

import com.s4.belsson.data.model.AnalysisResponse
import com.s4.belsson.data.model.AuthRequest
import com.s4.belsson.data.model.AuthResponse
import com.s4.belsson.data.model.MeasureRequest
import com.s4.belsson.data.model.MeasureResponse
import io.ktor.client.*
import io.ktor.client.call.*
import io.ktor.client.engine.android.*
import io.ktor.client.plugins.contentnegotiation.*
import io.ktor.client.plugins.logging.*
import io.ktor.client.request.*
import io.ktor.client.request.forms.*
import io.ktor.http.*
import io.ktor.serialization.kotlinx.json.*
import kotlinx.serialization.json.Json

/**
 * Ktor-based API service for communicating with the
 * Dental Implant Planning FastAPI backend.
 */
object ImplantApiService {

    // For emulator use "10.0.2.2"; for physical device use your machine's LAN IP
    private const val BASE_URL = "http://10.0.2.2:8001"

    private val json = Json {
        ignoreUnknownKeys = true
        isLenient = true
        prettyPrint = false
    }

    @Volatile
    private var authToken: String? = null

    val client = HttpClient(Android) {
        install(ContentNegotiation) {
            json(json)
        }
        install(Logging) {
            level = LogLevel.BODY
            logger = Logger.ANDROID
        }
        engine {
            connectTimeout = 60_000
            socketTimeout = 120_000
        }
    }

    /**
     * Upload a DICOM file for full jaw analysis.
     *
     * @param dicomBytes Raw bytes of the .dcm file
     * @param fileName   Original filename
     * @param toothX     Optional tooth X coordinate
     * @param toothY     Optional tooth Y coordinate
     */
    suspend fun analyzeJaw(
        dicomBytes: ByteArray,
        fileName: String,
        contentType: String = "application/dicom",
        toothX: Int? = null,
        toothY: Int? = null
    ): AnalysisResponse {
        val response = client.submitFormWithBinaryData(
            url = buildString {
                append("$BASE_URL/analyze-jaw")
                val params = mutableListOf<String>()
                toothX?.let { params.add("tooth_x=$it") }
                toothY?.let { params.add("tooth_y=$it") }
                if (params.isNotEmpty()) {
                    append("?${params.joinToString("&")}")
                }
            },
            formData = formData {
                append("file", dicomBytes, Headers.build {
                    append(HttpHeaders.ContentType, contentType)
                    append(HttpHeaders.ContentDisposition, "filename=\"$fileName\"")
                })
            }
        ) {
            applyAuthHeader()
        }

        if (!response.status.isSuccess()) {
            throw Exception("Server error: ${response.status}")
        }

        return response.body()
    }

    suspend fun analyzePanoramic(
        dicomBytes: ByteArray,
        fileName: String,
        contentType: String = "application/dicom",
        toothX: Int? = null,
        toothY: Int? = null
    ): AnalysisResponse {
        val response = client.submitFormWithBinaryData(
            url = buildString {
                append("$BASE_URL/analyze-panoramic")
                val params = mutableListOf<String>()
                toothX?.let { params.add("tooth_x=$it") }
                toothY?.let { params.add("tooth_y=$it") }
                if (params.isNotEmpty()) {
                    append("?${params.joinToString("&")}")
                }
            },
            formData = formData {
                append("file", dicomBytes, Headers.build {
                    append(HttpHeaders.ContentType, contentType)
                    append(HttpHeaders.ContentDisposition, "filename=\"$fileName\"")
                })
            }
        ) {
            applyAuthHeader()
        }

        if (!response.status.isSuccess()) {
            throw Exception("Server error: ${response.status}")
        }

        return response.body()
    }

    suspend fun signup(email: String, password: String): AuthResponse {
        val response = client.post("$BASE_URL/auth/signup") {
            contentType(ContentType.Application.Json)
            setBody(AuthRequest(email = email, password = password))
        }
        if (!response.status.isSuccess()) {
            throw Exception("Auth error: ${response.status}")
        }
        return response.body()
    }

    suspend fun login(email: String, password: String): AuthResponse {
        val response = client.post("$BASE_URL/auth/login") {
            contentType(ContentType.Application.Json)
            setBody(AuthRequest(email = email, password = password))
        }
        if (!response.status.isSuccess()) {
            throw Exception("Auth error: ${response.status}")
        }
        return response.body()
    }

    fun setAuthToken(token: String?) {
        authToken = token
    }

    /**
     * Measure bone metrics at a specific coordinate on a cached session.
     */
    suspend fun measure(sessionId: String, x: Int, y: Int): MeasureResponse {
        val response = client.post("$BASE_URL/measure") {
            contentType(ContentType.Application.Json)
            setBody(MeasureRequest(sessionId = sessionId, x = x, y = y))
            applyAuthHeader()
        }

        if (!response.status.isSuccess()) {
            throw Exception("Server error: ${response.status}")
        }

        return response.body()
    }

    private fun HttpRequestBuilder.applyAuthHeader() {
        authToken?.takeIf { it.isNotBlank() }?.let { token ->
            header(HttpHeaders.Authorization, "Bearer $token")
        }
    }
}

package com.s4.belsson.data.api

import com.s4.belsson.data.model.AnalysisResponse
import com.s4.belsson.data.model.AuthRequest
import com.s4.belsson.data.model.AuthResponse
import com.s4.belsson.data.model.MeasureRequest
import com.s4.belsson.data.model.MeasureResponse
import io.ktor.client.*
import io.ktor.client.call.*
import io.ktor.client.engine.android.*
import io.ktor.client.plugins.contentnegotiation.*
import io.ktor.client.plugins.logging.*
import io.ktor.client.request.*
import io.ktor.client.request.forms.*
import io.ktor.client.statement.bodyAsText
import io.ktor.http.*
import io.ktor.serialization.kotlinx.json.*
import kotlinx.serialization.json.Json

/**
 * Ktor-based API service for communicating with the
 * Dental Implant Planning FastAPI backend.
 */
object ImplantApiService {

    // For emulator use "10.0.2.2"; for physical device use your machine's LAN IP
    private const val BASE_URL = "http://10.0.2.2:8001"

    private val json = Json {
        ignoreUnknownKeys = true
        isLenient = true
        prettyPrint = false
        coerceInputValues = true
        explicitNulls = false
        allowSpecialFloatingPointValues = true
    }

    @Volatile
    private var authToken: String? = null

    val client = HttpClient(Android) {
        install(ContentNegotiation) {
            json(json)
        }
        install(Logging) {
            level = LogLevel.BODY
            logger = Logger.ANDROID
        }
        engine {
            connectTimeout = 60_000
            socketTimeout = 120_000
        }
    }

    /**
     * Upload a DICOM file for full jaw analysis.
     *
     * @param dicomBytes Raw bytes of the .dcm file
     * @param fileName   Original filename
     * @param toothX     Optional tooth X coordinate
     * @param toothY     Optional tooth Y coordinate
     */
    suspend fun analyzeJaw(
        dicomBytes: ByteArray,
        fileName: String,
        contentType: String = "application/dicom",
        toothX: Int? = null,
        toothY: Int? = null
    ): AnalysisResponse {
        val response = client.submitFormWithBinaryData(
            url = buildString {
                append("$BASE_URL/analyze-jaw")
                val params = mutableListOf<String>()
                toothX?.let { params.add("tooth_x=$it") }
                toothY?.let { params.add("tooth_y=$it") }
                if (params.isNotEmpty()) {
                    append("?${params.joinToString("&")}")
                }
            },
            formData = formData {
                append("file", dicomBytes, Headers.build {
                    append(HttpHeaders.ContentType, contentType)
                    append(HttpHeaders.ContentDisposition, "filename=\"$fileName\"")
                })
            }
        ) {
            applyAuthHeader()
        }

        if (!response.status.isSuccess()) {
            val detail = runCatching { response.bodyAsText() }.getOrDefault("")
            throw Exception("Server error: ${response.status} ${detail.take(300)}")
        }

        return response.body()
    }

    suspend fun analyzePanoramic(
        dicomBytes: ByteArray,
        fileName: String,
        contentType: String = "application/dicom",
        toothX: Int? = null,
        toothY: Int? = null
    ): AnalysisResponse {
        val response = client.submitFormWithBinaryData(
            url = buildString {
                append("$BASE_URL/analyze-panoramic")
                val params = mutableListOf<String>()
                toothX?.let { params.add("tooth_x=$it") }
                toothY?.let { params.add("tooth_y=$it") }
                if (params.isNotEmpty()) {
                    append("?${params.joinToString("&")}")
                }
            },
            formData = formData {
                append("file", dicomBytes, Headers.build {
                    append(HttpHeaders.ContentType, contentType)
                    append(HttpHeaders.ContentDisposition, "filename=\"$fileName\"")
                })
            }
        ) {
            applyAuthHeader()
        }

        if (!response.status.isSuccess()) {
            val detail = runCatching { response.bodyAsText() }.getOrDefault("")
            throw Exception("Server error: ${response.status} ${detail.take(300)}")
        }

        return response.body()
    }

    suspend fun signup(email: String, password: String): AuthResponse {
        val response = client.post("$BASE_URL/auth/signup") {
            contentType(ContentType.Application.Json)
            setBody(AuthRequest(email = email, password = password))
        }
        if (!response.status.isSuccess()) {
            throw Exception("Auth error: ${response.status}")
        }
        return response.body()
    }

    suspend fun login(email: String, password: String): AuthResponse {
        val response = client.post("$BASE_URL/auth/login") {
            contentType(ContentType.Application.Json)
            setBody(AuthRequest(email = email, password = password))
        }
        if (!response.status.isSuccess()) {
            throw Exception("Auth error: ${response.status}")
        }
        return response.body()
    }

    fun setAuthToken(token: String?) {
        authToken = token
    }

    /**
     * Measure bone metrics at a specific coordinate on a cached session.
     */
    suspend fun measure(sessionId: String, x: Int, y: Int): MeasureResponse {
        val response = client.post("$BASE_URL/measure") {
            contentType(ContentType.Application.Json)
            setBody(MeasureRequest(sessionId = sessionId, x = x, y = y))
            applyAuthHeader()
        }

        if (!response.status.isSuccess()) {
            val detail = runCatching { response.bodyAsText() }.getOrDefault("")
            throw Exception("Server error: ${response.status} ${detail.take(300)}")
        }

        return response.body()
    }

    private fun HttpRequestBuilder.applyAuthHeader() {
        authToken?.takeIf { it.isNotBlank() }?.let { token ->
            header(HttpHeaders.Authorization, "Bearer $token")
        }
    }
}

package com.s4.belsson.data.model

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

/**
 * Response from POST /analyze-jaw
 */
@Serializable
data class AnalysisResponse(
    @SerialName("session_id") val sessionId: String,
    val workflow: String = "cbct_implant",
    @SerialName("patient_name") val patientName: String,
    @SerialName("opg_image_base64") val opgImageBase64: String,
    @SerialName("nerve_path") val nervePath: List<NervePathPoint>,
    @SerialName("arch_path") val archPath: List<NervePathPoint> = emptyList(),
    @SerialName("planning_overlay") val planningOverlay: PlanningOverlay = PlanningOverlay(),
    @SerialName("bone_metrics") val boneMetrics: BoneMetrics,
    val metadata: DicomMetadata
)

@Serializable
data class NervePathPoint(
    val x: Int,
    val y: Int
)

@Serializable
data class OverlayLine(
    val start: NervePathPoint,
    val end: NervePathPoint
)

@Serializable
data class PlanningOverlay(
    @SerialName("outer_contour") val outerContour: List<NervePathPoint> = emptyList(),
    @SerialName("inner_contour") val innerContour: List<NervePathPoint> = emptyList(),
    @SerialName("base_guide") val baseGuide: List<NervePathPoint> = emptyList(),
    @SerialName("width_indicator") val widthIndicator: OverlayLine? = null,
    @SerialName("sector_lines") val sectorLines: List<OverlayLine> = emptyList(),
)

@Serializable
data class BoneMetrics(
    @SerialName("width_mm") val widthMm: Double,
    @SerialName("height_mm") val heightMm: Double,
    @SerialName("safe_height_mm") val safeHeightMm: Double,
    @SerialName("safety_margin_mm") val safetyMarginMm: Double,
    @SerialName("density_estimate_hu") val densityEstimateHu: Double,
    @SerialName("measurement_location") val measurementLocation: MeasurementLocation,
    @SerialName("safety_status") val safetyStatus: String = "warning",
    @SerialName("safety_reason") val safetyReason: String = ""
)

@Serializable
data class MeasurementLocation(
    val x: Int,
    val y: Int
)

@Serializable
data class DicomMetadata(
    @SerialName("pixel_spacing") val pixelSpacing: List<Double>,
    @SerialName("slice_thickness") val sliceThickness: Double,
    val rows: Int,
    val columns: Int,
    @SerialName("num_slices") val numSlices: Int,
    @SerialName("dataset_type") val datasetType: String = "unknown",
    val modality: String = "UNKNOWN",
    @SerialName("is_calibrated_hu") val isCalibratedHu: Boolean = false,
)

/**
 * Response from POST /measure
 */
@Serializable
data class MeasureResponse(
    @SerialName("bone_metrics") val boneMetrics: BoneMetrics,
    @SerialName("planning_overlay") val planningOverlay: PlanningOverlay = PlanningOverlay()
)

/**
 * Request body for POST /measure
 */
@Serializable
data class MeasureRequest(
    @SerialName("session_id") val sessionId: String,
    val x: Int,
    val y: Int
)

package com.s4.belsson.data.model

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

/**
 * Response from POST /analyze-jaw
 */
@Serializable
data class AnalysisResponse(
    @SerialName("session_id") val sessionId: String = "",
    val workflow: String = "cbct_implant",
    @SerialName("patient_name") val patientName: String = "Unknown",
    @SerialName("opg_image_base64") val opgImageBase64: String = "",
    @SerialName("nerve_path") val nervePath: List<NervePathPoint> = emptyList(),
    @SerialName("arch_path") val archPath: List<NervePathPoint> = emptyList(),
    @SerialName("planning_overlay") val planningOverlay: PlanningOverlay = PlanningOverlay(),
    @SerialName("bone_metrics") val boneMetrics: BoneMetrics = BoneMetrics(),
    val metadata: DicomMetadata = DicomMetadata()
)

@Serializable
data class NervePathPoint(
    val x: Int = 0,
    val y: Int = 0
)

@Serializable
data class OverlayLine(
    val start: NervePathPoint = NervePathPoint(),
    val end: NervePathPoint = NervePathPoint()
)

@Serializable
data class PlanningOverlay(
    @SerialName("outer_contour") val outerContour: List<NervePathPoint> = emptyList(),
    @SerialName("inner_contour") val innerContour: List<NervePathPoint> = emptyList(),
    @SerialName("base_guide") val baseGuide: List<NervePathPoint> = emptyList(),
    @SerialName("width_indicator") val widthIndicator: OverlayLine? = null,
    @SerialName("sector_lines") val sectorLines: List<OverlayLine> = emptyList(),
)

@Serializable
data class BoneMetrics(
    @SerialName("width_mm") val widthMm: Double = 3.0,
    @SerialName("height_mm") val heightMm: Double = 10.0,
    @SerialName("safe_height_mm") val safeHeightMm: Double = 8.0,
    @SerialName("safety_margin_mm") val safetyMarginMm: Double = 2.0,
    @SerialName("density_estimate_hu") val densityEstimateHu: Double = 0.0,
    @SerialName("measurement_location") val measurementLocation: MeasurementLocation = MeasurementLocation(),
    @SerialName("safety_status") val safetyStatus: String = "warning",
    @SerialName("safety_reason") val safetyReason: String = ""
)

@Serializable
data class MeasurementLocation(
    val x: Int = 0,
    val y: Int = 0
)

@Serializable
data class DicomMetadata(
    @SerialName("pixel_spacing") val pixelSpacing: List<Double> = listOf(1.0, 1.0),
    @SerialName("slice_thickness") val sliceThickness: Double = 1.0,
    val rows: Int = 0,
    val columns: Int = 0,
    @SerialName("num_slices") val numSlices: Int = 1,
    @SerialName("dataset_type") val datasetType: String = "unknown",
    val modality: String = "UNKNOWN",
    @SerialName("is_calibrated_hu") val isCalibratedHu: Boolean = false,
)

/**
 * Response from POST /measure
 */
@Serializable
data class MeasureResponse(
    @SerialName("bone_metrics") val boneMetrics: BoneMetrics = BoneMetrics(),
    @SerialName("planning_overlay") val planningOverlay: PlanningOverlay = PlanningOverlay()
)

/**
 * Request body for POST /measure
 */
@Serializable
data class MeasureRequest(
    @SerialName("session_id") val sessionId: String,
    val x: Int,
    val y: Int
)

private fun Double.safeFinite(default: Double): Double = if (isFinite()) this else default

fun AnalysisResponse.sanitized(): AnalysisResponse {
    val safeSpacing = metadata.pixelSpacing
        .takeIf { it.size >= 2 }
        ?.map { it.safeFinite(1.0).coerceAtLeast(0.01) }
        ?: listOf(1.0, 1.0)

    val safeMetrics = boneMetrics.copy(
        widthMm = boneMetrics.widthMm.safeFinite(3.0).coerceIn(3.0, 15.0),
        heightMm = boneMetrics.heightMm.safeFinite(10.0).coerceIn(10.0, 35.0),
        safeHeightMm = boneMetrics.safeHeightMm.safeFinite(8.0).coerceIn(0.0, 35.0),
        safetyMarginMm = boneMetrics.safetyMarginMm.safeFinite(2.0).coerceIn(0.0, 10.0),
        densityEstimateHu = boneMetrics.densityEstimateHu.safeFinite(0.0)
    )

    return copy(
        boneMetrics = safeMetrics,
        metadata = metadata.copy(
            pixelSpacing = safeSpacing,
            sliceThickness = metadata.sliceThickness.safeFinite(1.0).coerceAtLeast(0.01),
            rows = metadata.rows.coerceAtLeast(0),
            columns = metadata.columns.coerceAtLeast(0),
            numSlices = metadata.numSlices.coerceAtLeast(1)
        )
    )
}

fun MeasureResponse.sanitized(): MeasureResponse {
    val safeMetrics = boneMetrics.copy(
        widthMm = boneMetrics.widthMm.safeFinite(3.0).coerceIn(3.0, 15.0),
        heightMm = boneMetrics.heightMm.safeFinite(10.0).coerceIn(10.0, 35.0),
        safeHeightMm = boneMetrics.safeHeightMm.safeFinite(8.0).coerceIn(0.0, 35.0),
        safetyMarginMm = boneMetrics.safetyMarginMm.safeFinite(2.0).coerceIn(0.0, 10.0),
        densityEstimateHu = boneMetrics.densityEstimateHu.safeFinite(0.0)
    )
    return copy(boneMetrics = safeMetrics)
}

package com.s4.belsson.data.repository

import android.content.Context
import android.net.Uri
import android.provider.OpenableColumns
import com.s4.belsson.data.api.ImplantApiService
import com.s4.belsson.data.model.AnalysisResponse
import com.s4.belsson.data.model.AuthResponse
import com.s4.belsson.data.model.MeasureResponse
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.flow.flowOn

/**
 * Repository that bridges the Android layer (URIs, ContentResolver)
 * with the Ktor API service.
 */
class ImplantRepository(private val context: Context) {

    private val sessionStore = AuthSessionStore(context)

    init {
        ImplantApiService.setAuthToken(sessionStore.getToken())
    }

    enum class UploadWorkflow {
        CBCT_IMPLANT,
        PANORAMIC_MANDIBULAR_CANAL,
    }

    fun signup(email: String, password: String): Flow<Result<AuthResponse>> = flow {
        try {
            val response = ImplantApiService.signup(email.trim(), password)
            sessionStore.saveSession(response.token, response.user.email)
            ImplantApiService.setAuthToken(response.token)
            emit(Result.success(response))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    fun login(email: String, password: String): Flow<Result<AuthResponse>> = flow {
        try {
            val response = ImplantApiService.login(email.trim(), password)
            sessionStore.saveSession(response.token, response.user.email)
            ImplantApiService.setAuthToken(response.token)
            emit(Result.success(response))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    fun logout() {
        sessionStore.clearSession()
        ImplantApiService.setAuthToken(null)
    }

    fun getSavedEmail(): String? = sessionStore.getEmail()

    fun hasActiveSession(): Boolean = !sessionStore.getToken().isNullOrBlank()

    /**
     * Read a DICOM file from a content URI, upload it, and return the analysis.
     */
    fun analyzeJaw(
        uri: Uri,
        workflow: UploadWorkflow = UploadWorkflow.CBCT_IMPLANT,
    ): Flow<Result<AnalysisResponse>> = flow {
        try {
            val inputStream = context.contentResolver.openInputStream(uri)
                ?: throw IllegalArgumentException("Cannot open URI: $uri")

            val bytes = inputStream.use { it.readBytes() }

            // Resolve the real display name (e.g. "patient_cbct.dcm") from the
            // ContentResolver instead of parsing the opaque content:// URI path.
            val fileName = resolveFileName(uri, workflow)
            val contentType = resolveContentType(uri, workflow)

            val response = when (workflow) {
                UploadWorkflow.CBCT_IMPLANT -> ImplantApiService.analyzeJaw(
                    dicomBytes = bytes,
                    fileName = fileName,
                    contentType = contentType,
                )
                UploadWorkflow.PANORAMIC_MANDIBULAR_CANAL -> ImplantApiService.analyzePanoramic(
                    dicomBytes = bytes,
                    fileName = fileName,
                    contentType = contentType,
                )
            }

            emit(Result.success(response))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    /**
     * Measure bone at a specific (x, y) for a previously uploaded session.
     */
    fun measureAt(sessionId: String, x: Int, y: Int): Flow<Result<MeasureResponse>> = flow {
        try {
            val response = ImplantApiService.measure(sessionId, x, y)
            emit(Result.success(response))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    // ── Helpers ──────────────────────────────────────────────────────────────

    /**
     * Query the ContentResolver for DISPLAY_NAME. Falls back to the last
     * path segment and finally to "scan.dcm" so the backend always receives
     * a filename that ends in ".dcm".
     */
    private fun resolveFileName(uri: Uri, workflow: UploadWorkflow): String {
        // 1. Try ContentResolver (works for content:// URIs from Downloads, Files etc.)
        context.contentResolver.query(
            uri,
            arrayOf(OpenableColumns.DISPLAY_NAME),
            null, null, null
        )?.use { cursor ->
            if (cursor.moveToFirst()) {
                val nameIndex = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                if (nameIndex >= 0) {
                    val name = cursor.getString(nameIndex)
                    if (!name.isNullOrBlank()) {
                        return if (workflow == UploadWorkflow.CBCT_IMPLANT) {
                            ensureCbctInputName(name)
                        } else {
                            name
                        }
                    }
                }
            }
        }

        // 2. Fallback: last segment of the URI path
        val segment = uri.lastPathSegment
        if (!segment.isNullOrBlank()) {
            return if (workflow == UploadWorkflow.CBCT_IMPLANT) {
                ensureCbctInputName(segment)
            } else {
                segment
            }
        }

        // 3. Last resort
        return if (workflow == UploadWorkflow.CBCT_IMPLANT) "scan.dcm" else "scan"
    }

    /** Keep .zip/.dcm for CBCT study inputs, else fallback to .dcm for legacy support. */
    private fun ensureCbctInputName(name: String): String {
        val lower = name.lowercase()
        return when {
            lower.endsWith(".dcm") -> name
            lower.endsWith(".zip") -> name
            else -> "$name.dcm"
        }
    }

    private fun resolveContentType(uri: Uri, workflow: UploadWorkflow): String {
        val detected = context.contentResolver.getType(uri)?.lowercase().orEmpty()
        if (workflow == UploadWorkflow.PANORAMIC_MANDIBULAR_CANAL) {
            if (detected.startsWith("image/")) return detected
            val lowerName = resolveFileName(uri, workflow).lowercase()
            if (lowerName.endsWith(".png")) return "image/png"
            if (lowerName.endsWith(".jpg") || lowerName.endsWith(".jpeg")) return "image/jpeg"
            return if (detected.isNotBlank()) detected else "application/dicom"
        }

        val cbctName = resolveFileName(uri, workflow).lowercase()
        if (cbctName.endsWith(".zip")) return "application/zip"
        if (detected.contains("zip")) return "application/zip"
        return "application/dicom"
    }
}

package com.s4.belsson.data.repository

import android.content.Context
import android.net.Uri
import android.provider.OpenableColumns
import com.s4.belsson.data.api.ImplantApiService
import com.s4.belsson.data.model.AnalysisResponse
import com.s4.belsson.data.model.AuthResponse
import com.s4.belsson.data.model.MeasureResponse
import com.s4.belsson.data.model.sanitized
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.flow.flowOn

/**
 * Repository that bridges the Android layer (URIs, ContentResolver)
 * with the Ktor API service.
 */
class ImplantRepository(private val context: Context) {

    private val sessionStore = AuthSessionStore(context)

    init {
        ImplantApiService.setAuthToken(sessionStore.getToken())
    }

    enum class UploadWorkflow {
        CBCT_IMPLANT,
        PANORAMIC_MANDIBULAR_CANAL,
    }

    fun signup(email: String, password: String): Flow<Result<AuthResponse>> = flow {
        try {
            val response = ImplantApiService.signup(email.trim(), password)
            sessionStore.saveSession(response.token, response.user.email)
            ImplantApiService.setAuthToken(response.token)
            emit(Result.success(response))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    fun login(email: String, password: String): Flow<Result<AuthResponse>> = flow {
        try {
            val response = ImplantApiService.login(email.trim(), password)
            sessionStore.saveSession(response.token, response.user.email)
            ImplantApiService.setAuthToken(response.token)
            emit(Result.success(response))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    fun logout() {
        sessionStore.clearSession()
        ImplantApiService.setAuthToken(null)
    }

    fun getSavedEmail(): String? = sessionStore.getEmail()

    fun hasActiveSession(): Boolean = !sessionStore.getToken().isNullOrBlank()

    /**
     * Read a DICOM file from a content URI, upload it, and return the analysis.
     */
    fun analyzeJaw(
        uri: Uri,
        workflow: UploadWorkflow = UploadWorkflow.CBCT_IMPLANT,
    ): Flow<Result<AnalysisResponse>> = flow {
        try {
            val inputStream = context.contentResolver.openInputStream(uri)
                ?: throw IllegalArgumentException("Cannot open URI: $uri")

            val bytes = inputStream.use { it.readBytes() }

            // Resolve the real display name (e.g. "patient_cbct.dcm") from the
            // ContentResolver instead of parsing the opaque content:// URI path.
            val fileName = resolveFileName(uri, workflow)
            val contentType = resolveContentType(uri, workflow)

            val response = when (workflow) {
                UploadWorkflow.CBCT_IMPLANT -> ImplantApiService.analyzeJaw(
                    dicomBytes = bytes,
                    fileName = fileName,
                    contentType = contentType,
                )
                UploadWorkflow.PANORAMIC_MANDIBULAR_CANAL -> ImplantApiService.analyzePanoramic(
                    dicomBytes = bytes,
                    fileName = fileName,
                    contentType = contentType,
                )
            }

            emit(Result.success(response.sanitized()))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    /**
     * Measure bone at a specific (x, y) for a previously uploaded session.
     */
    fun measureAt(sessionId: String, x: Int, y: Int): Flow<Result<MeasureResponse>> = flow {
        try {
            val response = ImplantApiService.measure(sessionId, x, y)
            emit(Result.success(response.sanitized()))
        } catch (e: Exception) {
            emit(Result.failure(e))
        }
    }.flowOn(Dispatchers.IO)

    // ── Helpers ──────────────────────────────────────────────────────────────

    /**
     * Query the ContentResolver for DISPLAY_NAME. Falls back to the last
     * path segment and finally to "scan.dcm" so the backend always receives
     * a filename that ends in ".dcm".
     */
    private fun resolveFileName(uri: Uri, workflow: UploadWorkflow): String {
        // 1. Try ContentResolver (works for content:// URIs from Downloads, Files etc.)
        context.contentResolver.query(
            uri,
            arrayOf(OpenableColumns.DISPLAY_NAME),
            null, null, null
        )?.use { cursor ->
            if (cursor.moveToFirst()) {
                val nameIndex = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                if (nameIndex >= 0) {
                    val name = cursor.getString(nameIndex)
                    if (!name.isNullOrBlank()) {
                        return if (workflow == UploadWorkflow.CBCT_IMPLANT) {
                            ensureCbctInputName(name)
                        } else {
                            name
                        }
                    }
                }
            }
        }

        // 2. Fallback: last segment of the URI path
        val segment = uri.lastPathSegment
        if (!segment.isNullOrBlank()) {
            return if (workflow == UploadWorkflow.CBCT_IMPLANT) {
                ensureCbctInputName(segment)
            } else {
                segment
            }
        }

        // 3. Last resort
        return if (workflow == UploadWorkflow.CBCT_IMPLANT) "scan.dcm" else "scan"
    }

    /** Keep .zip/.dcm for CBCT study inputs, else fallback to .dcm for legacy support. */
    private fun ensureCbctInputName(name: String): String {
        val lower = name.lowercase()
        return when {
            lower.endsWith(".dcm") -> name
            lower.endsWith(".zip") -> name
            else -> "$name.dcm"
        }
    }

    private fun resolveContentType(uri: Uri, workflow: UploadWorkflow): String {
        val detected = context.contentResolver.getType(uri)?.lowercase().orEmpty()
        if (workflow == UploadWorkflow.PANORAMIC_MANDIBULAR_CANAL) {
            if (detected.startsWith("image/")) return detected
            val lowerName = resolveFileName(uri, workflow).lowercase()
            if (lowerName.endsWith(".png")) return "image/png"
            if (lowerName.endsWith(".jpg") || lowerName.endsWith(".jpeg")) return "image/jpeg"
            return if (detected.isNotBlank()) detected else "application/dicom"
        }

        val cbctName = resolveFileName(uri, workflow).lowercase()
        if (cbctName.endsWith(".zip")) return "application/zip"
        if (detected.contains("zip")) return "application/zip"
        return "application/dicom"
    }
}

